'use client';

import { ChevronDown, Plus } from 'lucide-react';
import { useState } from 'react';

interface AccordionProps {
  title: string;
  children?: React.ReactNode;
}

export default function Accordion({ title, children }: AccordionProps) {
  const [isOpen, setIsOpen] = useState(false);
  return (
    <article className="flex w-full flex-col rounded-md lg:p-4">
      <button className="cursor-pointer self-end border-b border-b-primary pb-2 mb-4" onClick={() => setIsOpen(!isOpen)}>
        <Plus />
      </button>

      {isOpen && <>{children}</>}
    </article>
  );
}
